import{_ as e,o as r,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Windows SDK Overview","description":"","frontmatter":{"title":"Windows SDK Overview","slug":"windows-cpp-sdk-overview"},"headers":[],"relativePath":"developer-hub/windows-cpp-sdk-overview.md","filePath":"developer-hub/windows-cpp-sdk-overview.md"}'),o={name:"developer-hub/windows-cpp-sdk-overview.md"};function i(s,t,d,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[n('<h3 id="sdk-stats" tabindex="-1">SDK Stats <a class="header-anchor" href="#sdk-stats" aria-label="Permalink to &quot;SDK Stats&quot;">​</a></h3><p><strong>Open Source Github Repo</strong>: <a href="https://github.com/BranchMetrics/cpp-branch-deep-linking-attribution" target="_blank" rel="noreferrer">https://github.com/BranchMetrics/cpp-branch-deep-linking-attribution</a></p><p><strong>Minimum Visual Studio</strong> version 2019+</p><h3 id="branch-demo-app" tabindex="-1">Branch Demo App <a class="header-anchor" href="#branch-demo-app" aria-label="Permalink to &quot;Branch Demo App&quot;">​</a></h3><p><strong>Want to take our technology for a test drive before implementing it?</strong></p><p><a href="https://github.com/BranchMetrics/cpp-branch-deep-linking-attribution/tree/master/BranchSDK-Samples/TestBed" target="_blank" rel="noreferrer">VIEW BRANCH TESTBED GITHUB</a></p><h3 id="basic-integration" tabindex="-1">Basic Integration <a class="header-anchor" href="#basic-integration" aria-label="Permalink to &quot;Basic Integration&quot;">​</a></h3><p>For steps on how to integrate the Branch Web SDK and validate your integration, visit our Basic Integration guide.</p><p><a href="https://help.branch.io/developers-hub/docs/windows-cpp-basic-integration" target="_blank" rel="noreferrer">INTEGRATE THE BRANCH SDK</a></p><h3 id="testing-implementation" tabindex="-1">Testing Implementation <a class="header-anchor" href="#testing-implementation" aria-label="Permalink to &quot;Testing Implementation&quot;">​</a></h3><p><strong>Test your Branch integration before your app goes live.</strong></p><p><a href="./windows-cpp-testing.html">TEST THE INTEGRATION</a></p><h3 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to &quot;Version History&quot;">​</a></h3><p><strong>View past versions of the Branch SDK for Win32 C++ including changes.</strong></p><p><a href="./windows-cpp-version-history.html">VIEW VERSION HISTORY</a></p><h3 id="sdk-functionality" tabindex="-1">SDK Functionality <a class="header-anchor" href="#sdk-functionality" aria-label="Permalink to &quot;SDK Functionality&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Functionality</th><th>Description</th><th>Supported</th></tr></thead><tbody><tr><td>Deep Linking</td><td><strong>What:</strong> Branch’s deep links store contextual information about where a user wants to go, where the link was clicked, who originally shared the link, and an almost unlimited amount of custom data. <strong>Why:</strong> This empowers you to build powerful personalization features to provide users better experiences and happier, stickier users.</td><td>✅</td></tr><tr><td>Deferred Deep Linking</td><td><strong>What:</strong> Deep link users to relevant content immediately after first install. <strong>Why:</strong> Deferred deep linking allows a user to click on a link, install an app associated with the link, and then visit the content associated with that link in the newly installed app. <strong>Deferred deep linking is inherently included in Branch&#39;s deep linking capabilities. There is no additional setup!</strong></td><td>✅</td></tr><tr><td>Intelligent Fallback Logic</td><td><strong>What:</strong> Branch routes users based on the link behaviors you specify in your account. This includes redirects for android (phone + tablet), ios (phone + tablet), desktop (Mac + Windows), and social media previews. <strong>Why:</strong> Branch&#39;s behavior for desktop link redirects is under development pending user testing. Currently, if the URI scheme provided does not load, the end user will experience a blank page.</td><td>❌</td></tr><tr><td>Send to Desktop App Store When App Not Installed</td><td><strong>What:</strong> At this time, Branch will route users without your native desktop app to your Default Desktop URL instead of the Desktop App Store. The option to route users to the Desktop App Store instead of your Default Desktop URL is on the product roadmap.</td><td>❌</td></tr><tr><td>Universal Links</td><td><strong>What:</strong> Universal Links serve as standard web links (i.e., <a href="http://www.branch.io" target="_blank" rel="noreferrer">www.branch.io</a>), but point to a website page and content in the app. This standard was invented to provide developers with a graceful fallback if the app was not installed on a user&#39;s phone, and to remove URI schemes from the mobile ecosystem.</td><td>❌</td></tr><tr><td>Branch Universal Objects (BUO)</td><td><strong>What:</strong> The Branch Universal Object represents content to be shared or indexed with Branch. It acts as a container upon which all metadata and link properties are passed in and carried to your application.</td><td>❌</td></tr><tr><td>Branch Standard Events</td><td><strong>What:</strong> Branch Win32 C++ SDK tracks clicks, opens, installs, reinstalls and impressions automatically (out-of-the-box). However, Branch supports 25 standard events covering commerce, content and lifestyle events that you can measure. <strong>Why:</strong> By measuring a wide variety of events, you can more efficiently optimize both the functionality of your app and your advertising strategies. Measuring events and understanding how your users interact with your app directly impacts your ability to build effective and ROI positive advertising campaigns by enabling you to compare retention, engagement and LTV to your costs.</td><td>✅</td></tr><tr><td>Branch Custom Events</td><td><strong>What:</strong> Custom events are simply events at are unique to your app and therefore require custom implementation to accurately capture. <strong>Why:</strong> By measuring a wide variety of events, you can more efficiently optimize both the functionality of your app and your advertising strategies. Measuring events and understanding how your users interact with your app directly impacts your ability to build effective and ROI positive advertising campaigns by enabling you to compare retention, engagement and LTV to your costs.</td><td>✅</td></tr><tr><td>Dedicated Redirect Parameters</td><td><strong>What:</strong> In addition to the default redirects you have in place at the app-level, you can also use a dedciated redirect parameter at the link-level. When this platform-specific parameter is manually added to a link, Branch routes any user who clicks on it to the destination URL you provide; overriding the default redirect settings at the app-level. <strong>Why:</strong> Give yourself the flexibility to control where your users are sent to when you want a different experience than the default landing page you&#39;ve specified at the app-level. Particularly useful when running campaigns targeting a non-standard use case as you don&#39;t have to change your global redirect settings.</td><td>✅</td></tr><tr><td>Persist User Identities</td><td><strong>What:</strong> Often, you might have your own user IDs, or want referral and event data to persist across platforms or the uninstall/reinstall of your app. <strong>Why:</strong> Persisting a user&#39;s identity can be very helpful to asses if your users access your service from different devices, thereby providing a more complete story of your user.</td><td>✅</td></tr><tr><td>Disable User Tracking</td><td><strong>What:</strong> If a user indicates that they want to limit collection of their data on your app or website, or if you otherwise determine that a particular end user’s data should not be collected or otherwise processed, you can continue to make use of the Branch’s SDK (e.g. for creating and sharing Branch Links) while not tracking that end user. <strong>Why:</strong> We collect limited device information to power our deep linking technology and to provide attribution and analytics services. However, we understand that some end-users would like to opt out of this data processing; and, in other cases, the law (or Branch’s policies) do not permit that certain types of personal data for certain end users be provided to Branch (for example, data relating to children under the age of 13).</td><td>✅</td></tr><tr><td>Short Links</td><td><strong>What:</strong> Short Links are the most common deep link and are highly customizeable. You can customize the subdomain of <code>example.app.link</code>,change to your own personal domain <code>links.yoursite.com</code>, or tailor the appearance of the Short Link to a custom alias during creation (e.g. <code>https://example.app.link/october-sale</code>). <strong>Why:</strong> Short Links allow you to present branded, short and to the point links that are visually easy to digest.</td><td>✅</td></tr><tr><td>Push Notifications</td><td><strong>What:</strong> Deep link into specific app content directly from a push notification on the user&#39;s device.</td><td>❌</td></tr><tr><td>Last Attributed Touch Data (LATD)</td><td><strong>What:</strong> Last attributed touch data contains the information associated with that user&#39;s last viewed impression or clicked link.</td><td>❌</td></tr><tr><td>SDK Logging</td><td><strong>What:</strong> The Branch SDK for macOS is instrumented with a built-in logger so you can log API calls you make with the SDK. <strong>Why:</strong> Turning the logger on allows you to surface request and response bodies, that are JSON formatted.</td><td>✅</td></tr></tbody></table>',17)])])}const g=e(o,[["render",i]]);export{u as __pageData,g as default};
